LIB = ROOT / "scripts" / "suno-lib.sh"
SEED_ENGINE = ROOT / "scripts" / "suno-seed-engine.py"
TARGET_TRACKS_PER_ALBUM = 8
# Per-album track-count overrides (album name -> target takes). Lets an album close out
# at fewer tracks so the queue stops re-trying it and frees the rest of the batch.
ALBUM_TARGET_OVERRIDES = {}

def target_for_album(album_name: str) -> int:
    return ALBUM_TARGET_OVERRIDES.get(album_name, TARGET_TRACKS_PER_ALBUM)

