def load_state():
    if STATE.exists():
        return json.loads(STATE.read_text(encoding="utf-8"))
    return {"next_genre": 0, "next_job": 0, "runs": [], "done": False}


def save_state(state):
    STATE.parent.mkdir(parents=True, exist_ok=True)
    tmp = STATE.with_suffix(".json.tmp")
    tmp.write_text(json.dumps(state, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    tmp.replace(STATE)


def run(cmd):
    env = dict(__import__("os").environ)
    # Snap Chromium may start only with sandbox/dev-shm flags; use this when the CLI captcha solver launches Chrome.
    env.setdefault("CHROME_PATH", str(ROOT / "scripts" / "chrome-for-suno.sh"))
    env.setdefault("SUNO_CHROME_PATH", str(ROOT / "scripts" / "chrome-for-suno.sh"))
    env.setdefault("CHROME_FLAGS", "--no-sandbox --disable-dev-shm-usage --disable-gpu --no-zygote")
    env.setdefault("SUNO_CHROME_FLAGS", "--no-sandbox --disable-dev-shm-usage --disable-gpu --no-zygote")
    proc = subprocess.run(cmd, cwd=str(ROOT), text=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, env=env)
    return proc.returncode, proc.stdout, proc.stderr


def slugify(text: str) -> str:
    text = text.replace("đ", "d").replace("Đ", "D")
    text = ''.join(ch for ch in unicodedata.normalize('NFKD', text) if not unicodedata.combining(ch))
    text = re.sub(r'[^A-Za-z0-9]+', '-', text).strip('-')
    return re.sub(r'-+', '-', text) or 'untitled'


def update_evolution_memory(project_dir, job, lyric_path):
    audit_code, audit_out, audit_err = run([
        str(ROOT / "scripts" / "suno-audit.py"),
        "--project", str(project_dir),
        "--style", job["tags"],
        "--lyrics-file", str(lyric_path),
        "--exclude", job.get("exclude", "generic stock loop, karaoke backing track, muddy mix, weak hook"),
        "--weirdness", str(job.get("weirdness", 62)),
        "--style-influence", str(job.get("style_influence", 86)),
    ])
    lyric_code, lyric_out, lyric_err = run([
        str(ROOT / "scripts" / "suno-lyric-audit.py"),
        "--project", str(project_dir),
        "--lyrics-file", str(lyric_path),
    ])
    mem_path = ROOT / "suno-library" / "maestro-evolution.json"
    try:
        audit = json.loads(audit_out) if audit_out.strip() else {"score": None, "lessons": [audit_err[-500:]]}
    except Exception:
        audit = {"score": None, "lessons": [audit_out[-500:], audit_err[-500:]]}
    try:
        lyric_audit = json.loads(lyric_out) if lyric_out.strip() else {"score": None, "lessons": [lyric_err[-500:]]}
    except Exception:
        lyric_audit = {"score": None, "lessons": [lyric_out[-500:], lyric_err[-500:]]}
    mem = json.loads(mem_path.read_text(encoding="utf-8")) if mem_path.exists() else {"schema_version": "1.0", "runs": [], "active_rules": []}
    mem.setdefault("runs", []).append({
        "at": datetime.now(timezone.utc).astimezone().isoformat(timespec="seconds"),
        "project_dir": str(project_dir),
        "title": job["title"],
        "genre": project_dir.parents[0].name,
        "audit_score": audit.get("score"),
        "lyric_audit_score": lyric_audit.get("score"),
        "missing": audit.get("missing", []),
        "lyric_missing": lyric_audit.get("missing", []),
        "lessons": audit.get("lessons", []),
        "lyric_lessons": lyric_audit.get("lessons", []),
    })
    rules = set(mem.get("active_rules", []))
    for lesson in audit.get("lessons", []):
        rules.add(str(lesson))
    for lesson in lyric_audit.get("lessons", []):
        rules.add("LYRIC: " + str(lesson))
    mem["active_rules"] = sorted(rules)[-50:]
    mem["updated_at"] = datetime.now(timezone.utc).astimezone().isoformat(timespec="seconds")
    mem_path.write_text(json.dumps(mem, ensure_ascii=False, indent=2)+"\n", encoding="utf-8")
    return audit_code


def album_track_count(album_name: str) -> int:
    count = 0
    for meta_path in (ROOT / "suno-library").glob("*/*/metadata.json"):
        try:
            meta = json.loads(meta_path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if meta.get("album") == album_name:
            count += len(meta.get("takes", []))
    return count

