def extra_job_for(album, job_index):
    genre = album["genre"]
    local_extra = EXTRA_JOBS.get(genre, [])
    extra_i = max(0, job_index - len(album["jobs"]))
    if extra_i < len(local_extra):
        return local_extra[extra_i]
    base_title, base_tags = GENRE_EXTRA_STYLE.get(genre, (f"{genre} Bí Mật {extra_i+1}", f"Hyper-realistic Vietnamese {genre} fusion, 100 BPM distinctive groove, expressive lead vocal, memorable hook, detailed drums and bass, signature instrumental motif, polished master, emotional arc"))
    title = base_title if extra_i == 0 else f"{base_title} {extra_i+1}"
    lyrics = f"[Intro - signature motif, cinematic entrance]\nMột làn gió mở cửa âm thanh\nTên bài vang lên rất xanh\n\n[Verse 1 - focused lead vocal, low-to-mid energy]\nTa đi qua ngày dài nhiều bụi\nNhặt một câu hát ở ven đường\nCó điều tưởng như rất cũ\nBỗng sáng lên giữa đời thường\n\n[Pre-Chorus - harmony enters, tension builds]\nNếu tim còn biết gọi\nThì đêm chưa thể tàn\n\n[Chorus - big memorable hook, doubled vocal, full drums]\n{title}\nGọi ta về giữa ánh sáng\n{title}\nMở ra trời rất khác\n\n[Verse 2 - denser delivery, added percussion layer]\nMỗi bước chân thêm một nhịp\nMỗi vết đau hóa một lời\nTa không còn hát cho mất mát\nTa hát cho mình hồi sinh thôi\n\n[Bridge - stripped arrangement, emotional turn]\nLặng đi một chút để nghe sâu hơn\nRồi bật lên như bình minh rất lớn\n\n[Final Chorus - bigger hook, ad-libs, stacked harmonies]\n{title}\nGọi ta về giữa ánh sáng\n{title}\nMở ra trời rất khác\n\n[Outro - motif returns, clean ending]\nMột làn gió khép lại âm thanh\nTrong lòng còn sáng rất xanh"
    return {"title": title, "tags": base_tags, "lyrics": lyrics}

def load_seeded_job(album, base_job, job_index):
    """Upgrade every generation with fresh concept seed, style chain, lyric variation."""
    code, out, err = run([str(SEED_ENGINE), "--genre", album["genre"], "--title", base_job["title"], "--iteration", str(job_index)])
    if code != 0:
        # Safe fallback: original job still runs, but record the seed failure in title metadata via stderr.
        return base_job
    try:
        seed = json.loads(out)
    except Exception:
        return base_job
    upgraded = dict(base_job)
    upgraded["title"] = seed.get("title") or base_job["title"]
    upgraded["tags"] = seed.get("style_prompt") or base_job["tags"]
    upgraded["lyrics"] = seed.get("lyrics") or base_job["lyrics"]
    upgraded["exclude"] = seed.get("exclude", base_job.get("exclude", "generic stock loop, karaoke backing track, muddy mix, weak hook"))
    upgraded["weirdness"] = seed.get("weirdness", base_job.get("weirdness", 62))
    upgraded["style_influence"] = seed.get("style_influence", base_job.get("style_influence", 86))
    upgraded["idea_seed"] = seed.get("idea_seed", {})
    return upgraded

def main():
    state = load_state()
    if state.get("done"):
        print(json.dumps({"status": "done", "message": "All planned album jobs completed"}, ensure_ascii=False))
        return 0

    # Pick priority albums first, then the rest. User wants new albums filled before continuing older genres.
    priority_order = [g for g in PRIORITY_GENRES] + [a["genre"] for a in PLAN if a["genre"] not in PRIORITY_GENRES]
    # Build the ordered list of all incomplete albums so a guard-blocked album can be skipped
    # instead of aborting the whole batch (otherwise one stuck album starves the entire queue).
    incomplete = []
    for wanted_genre in priority_order:
        for idx, candidate in enumerate(PLAN):
            if candidate["genre"] != wanted_genre:
                continue
            tracks = album_track_count(candidate["album"])
            if tracks < target_for_album(candidate["album"]):
                incomplete.append((idx, candidate, tracks))

    if not incomplete:
        state["done"] = True
        save_state(state)
        print(json.dumps({"status": "done", "message": "All albums reached target tracks", "target_tracks_per_album": TARGET_TRACKS_PER_ALBUM}, ensure_ascii=False))
        return 0

    gi = None
    ji = None
    album = None
    job = None
    lyric_path = None
    skipped = []
    LYRICS_DIR.mkdir(parents=True, exist_ok=True)

    for (idx, candidate, tracks) in incomplete:
        cand_ji = tracks // TAKES_PER_JOB
        base_job = candidate["jobs"][cand_ji] if cand_ji < len(candidate["jobs"]) else extra_job_for(candidate, cand_ji)
        cand_job = load_seeded_job(candidate, base_job, cand_ji)
        cand_lyric = LYRICS_DIR / f"{candidate['genre']}_{cand_ji+1:02d}_{cand_job['title'].replace(' ', '_')}.txt"
        cand_lyric.write_text(cand_job["lyrics"], encoding="utf-8")

        # Structure gate first: clean JSON/code-fence pollution and require rich [section] tags.
        run([str(ROOT / "scripts" / "suno-structure-guard.py"), "--lyrics-file", str(cand_lyric), "--fix"])

        # Hard diversity gate: if the candidate is too similar to recent same-genre work, reseed up to 8 times.
        passed = False
        for reseed in range(8):
            s_code, s_out, s_err = run([str(ROOT / "scripts" / "suno-structure-guard.py"), "--lyrics-file", str(cand_lyric), "--fix"])
            d_code, d_out, d_err = run([str(ROOT / "scripts" / "suno-prev-lyric-guard.py"), "--genre", candidate["genre"], "--lyrics-file", str(cand_lyric)])
            if d_code == 0 and s_code == 0:
                passed = True
                break
            base_job = extra_job_for(candidate, cand_ji + reseed + 1)
            cand_job = load_seeded_job(candidate, base_job, cand_ji + reseed + 1)
            cand_lyric = LYRICS_DIR / f"{candidate['genre']}_{cand_ji+1:02d}_{cand_job['title'].replace(' ', '_')}.txt"
            cand_lyric.write_text(cand_job["lyrics"], encoding="utf-8")

        if passed:
            gi, ji, album, job, lyric_path = idx, cand_ji, candidate, cand_job, cand_lyric
            break
        # Guard blocked this album for all 8 reseeds: record a skip and try the next incomplete album.
        skip_record = {"at": datetime.now(timezone.utc).astimezone().isoformat(timespec="seconds"), "genre": candidate["genre"], "album": candidate["album"], "title": cand_job["title"], "exit_code": 3, "stderr_tail": "diversity guard rejected 8 reseeds (skipped, trying next album)"}
        state.setdefault("runs", []).append(skip_record)
        skipped.append({"genre": candidate["genre"], "album": candidate["album"], "title": cand_job["title"]})

    if album is None:
        # Every incomplete album is currently guard-blocked. Persist skips and report (no generation claimed).
        save_state(state)
        print(json.dumps({"status": "error", "message": "all incomplete albums blocked by diversity guard", "skipped": skipped, "exit_code": 3}, ensure_ascii=False, indent=2))
        return 3

    # Create local album manifest once per album.
    if ji == 0:
        run([str(LIB), "album", "create", album["album"], "--genre", album["genre"], "--description", "Auto-generated album batch: 8 tracks per genre/album."])

    cmd = [
        str(LIB), "generate",
        "--genre", album["genre"],
        "--title", job["title"],
        "--tags", job["tags"],
        "--exclude", job.get("exclude", "generic stock loop, karaoke backing track, muddy mix, weak hook"),
        "--weirdness", str(job.get("weirdness", 62)),
        "--style-influence", str(job.get("style_influence", 86)),
        "--lyrics-file", str(lyric_path),
        "--album", album["album"],
        "--wait", "--download",
    ]
    if album["genre"] in ["Instrumental", "Relax-Sleep", "Restaurant-Jazz-Instrument"]:
        cmd.append("--instrumental")
    code, out, err = run(cmd)
    record = {
        "at": datetime.now(timezone.utc).astimezone().isoformat(timespec="seconds"),
        "genre": album["genre"],
        "album": album["album"],
        "title": job["title"],
        "idea_seed": job.get("idea_seed", {}),
        "command": cmd,
        "exit_code": code,
        "stdout_tail": out[-4000:],
        "stderr_tail": err[-4000:],
    }
    state.setdefault("runs", []).append(record)
    if code == 0:
        # Audit prompt richness and store lessons in metadata + global Maestro evolution memory.
        project_dir = ROOT / "suno-library" / album["genre"] / f"{datetime.now().strftime('%Y-%m-%d')}_{slugify(job['title'])}"
        if project_dir.exists():
            update_evolution_memory(project_dir, job, lyric_path)
        run([str(ROOT / "scripts" / "suno-playlist-refresh.py")])
        run([str(ROOT / "scripts" / "suno-remote-playlist-sync.py")])
        run([str(ROOT / "scripts" / "suno-evolution-report.py")])
        # Store an advisory next pointer, but actual next run is selected by album track counts.
        state["next_genre"] = gi
        state["next_job"] = ji + 1
        state["target_tracks_per_album"] = TARGET_TRACKS_PER_ALBUM
        if all(album_track_count(a["album"]) >= target_for_album(a["album"]) for a in PLAN):
            state["done"] = True
    if code != 0:
        fail_text = (err + "\n" + out).lower()
        if any(k in fail_text for k in ["captcha", "hcaptcha", "login", "network-error", "never finished loading"]):
            d_code, d_out, d_err = run([str(ROOT / "scripts" / "suno-diagnostic-screenshot.py"), "--reason", "batch_failure_captcha_or_login"])
            record["diagnostic_exit_code"] = d_code
            record["diagnostic_stdout"] = d_out[-2000:]
            record["diagnostic_stderr"] = d_err[-2000:]
            state["runs"][-1] = record
    save_state(state)
    print(json.dumps({"status": "ok" if code == 0 else "error", "record": record, "next_genre": state.get("next_genre"), "next_job": state.get("next_job"), "done": state.get("done", False)}, ensure_ascii=False, indent=2))
    return code

if __name__ == "__main__":
    sys.exit(main())
